var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"카린 웡! 작전 브리핑을 준비하기 위해, 13시 정각에 도착하였습니다! 이에 신고합니다!","JPN":"カリン・ウォン！　ブリーフィングを準備するため、13時定刻に到着しましたことをご報告いたします！","ENG":"Karin Wong! Reporting for duty at 13:00! Ready for the mission briefing!","TWN":"報告！卡琳，13點準時抵達準備作戰簡報！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"……알고 있겠지, 소령. 사태는 일각을 다툰다.","JPN":"……わかっているだろうな、少佐。事態は一刻を争う。","ENG":"...I'm sure you're well aware, Major. There is not a moment to be lost.","TWN":"……你應該也知道，現在情況很嚴重，少校。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"예상보다 일찍 고치에서 깨어난 네피림을 막기 위해, 전 세계가 총력을 다해 시간을 벌어주고 있다.","JPN":"予想より早く繭から目覚めたネフィリムを止めるため、全世界が総力を挙げて時間を稼いでくれている。","ENG":"The Nephil came out of the cocoon earlier than expected, and the whole world is using all its resources to give us time to stop it.","TWN":"為要阻止比預期還要早從繭中甦醒的諾菲力，全世界都在拼命爭取時間。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그리고…….","JPN":"それに……","ENG":"And...","TWN":"還有……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"네피림과의 지난 전투에서 큰 부상을 입었던 사령관님이……","JPN":"この前、ネフィリムとの戦闘で大怪我を負った司令官が……","ENG":"Our commander, who suffered a grave injury from the last battle with the Nephil...","TWN":"在上一次和諾菲力的戰鬥中身負重傷的司令官……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"오늘 새벽…… 명을 달리하셨다.","JPN":"今日の未明……亡くなられた。","ENG":"Last night, he... passed away.","TWN":"在今天淩晨……離世。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"사령관님이…….","JPN":"司令官が……","ENG":"Commander...","TWN":"司令官……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"따라서…… 전시 상황이기에 특별한 인사조치 없이, 일시적으로 내가 사령관을 맡게 되었다.","JPN":"よって……戦時下のため特別な人事措置なしに、俺が臨時の司令官を引き受けることになった。","ENG":"Therefore... I've been assigned the temporary title of commander without any particular transfer, considering the fact that we are in times of war.","TWN":"……因為是戰時，所以在沒有特別人事調動的情況下，暫時由我擔任司令官。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이걸로…… 델타 세븐은 너와 나 둘 밖에 남지 않았군.","JPN":"これで……デルタセブンは俺とお前、二人だけになったな。","ENG":"This means... you and I are the only remaining members of Delta Seven.","TWN":"因此……第七三角洲部隊就只剩下你和我二個人。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하지만 긍지 높은 델타 세븐의 대원인 이상, 우리는 슬퍼하거나 망설일 겨를 따위 없다.","JPN":"だが誇り高きデルタセブンの隊員である以上、俺たちは悲しんだり、戸惑っている暇などない。","ENG":"However, as proud members of Delta Seven, we have no time to grieve or hesitate.","TWN":"但身為榮耀的第七三角洲部隊隊員，我們無暇為此悲傷或猶豫。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"지금 이 시각에도 수없이 사람이 죽어나가고 있다.","JPN":"今この時にも、数多くの人が死んでいる。","ENG":"Even at this very moment, people are dying.","TWN":"現在這一刻也有無數人正在死去。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"알고 있겠지, 소령. 우리는 그들을 구해야만 하는 의무가 있어.","JPN":"わかっているだろうな、少佐。俺たちは彼らを救う義務がある。","ENG":"I don't need to say it twice, do I, Major? Our duty is to save them.","TWN":"你明白吧，少校。我們有義務拯救他們。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네……! 알고 있습니다!","JPN":"はい……！　わかっています！","ENG":"Yes...! I am aware!","TWN":"是……！我明白！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"좋다, 소령. 그렇다면 이번 작전을 위해 계약한 용병들을 소개하겠다.","JPN":"よろしい、少佐。それでは、今度の作戦のために契約した傭兵たちを紹介しよう。","ENG":"Very well, Major. Then let me introduce the mercenaries we've hired for this operation.","TWN":"很好，少校，我替你介紹一下這次作戰我們特別雇用的傭兵。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"요, 용병……?","JPN":"よ、傭兵……？","ENG":"M-mercenaries...?","TWN":"傭，傭兵……？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이야, 이거 영광이네요. 죽기전에 이렇게 말끔한 기지에서 미팅도 다 해보고.","JPN":"いやぁ、光栄です。死ぬ前にこんなキレイな基地でミーティングもできるなんて。","ENG":"Wow, what an honor, getting to attend a meeting at such a neat base before I die!","TWN":"哇，真是榮幸，沒想到死前能在這麼乾淨的基地參加會議。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};